const d = $input.first().json;
const body = d.body || d;
const msgType = body.type || 'text';
const hasDoc = ['document','image','audio','video'].includes(msgType);
return [{ json: {
  source_channel: 'whatsapp',
  sender_id: body.from || 'unknown',
  sender_email: null,
  has_document: hasDoc,
  text: body.text?.body || body.caption || '',
  subject: 'WhatsApp message',
  filename: body.document?.filename || body.image?.filename || null,
  media_id: body.document?.id || body.image?.id || null,
  attachment_key: hasDoc ? 'attachment_0' : null,
  raw: d
}, binary: $input.first().binary || {} }];

const d = $input.first().json;
const msg = d.message || d;
const hasDoc = !!(msg.document || msg.photo);
return [{ json: {
  source_channel: 'telegram',
  sender_id: String(msg.from?.id || msg.chat?.id || 'unknown'),
  sender_email: null,
  has_document: hasDoc,
  text: msg.text || msg.caption || '',
  subject: 'Telegram from ' + (msg.from?.username || msg.from?.first_name || 'unknown'),
  filename: msg.document?.file_name || (msg.photo ? 'photo.jpg' : null),
  file_id: msg.document?.file_id || (msg.photo && msg.photo[msg.photo.length-1]?.file_id) || null,
  attachment_key: hasDoc ? 'attachment_0' : null,
  raw: d
}, binary: $input.first().binary || {} }];

const d = $input.first().json;
const b = $input.first().binary || {};
const attachKey = Object.keys(d).find(k => k.startsWith('attachment_')) || Object.keys(b).find(k => k.startsWith('attachment_')) || null;
const hasDoc = !!attachKey;
return [{ json: {
  source_channel: 'gmail',
  sender_id: d.from || 'unknown',
  sender_email: d.from || null,
  has_document: hasDoc,
  text: d.text || d.snippet || '',
  subject: d.subject || '',
  filename: (attachKey && b[attachKey]) ? b[attachKey].fileName : null,
  attachment_key: attachKey,
  raw: d
}, binary: b }];

const d = $input.first().json;
const b = $input.first().binary || {};
const attachKey = Object.keys(b).find(k => k.startsWith('attachment_')) || null;
const hasDoc = d.hasAttachments === true || !!attachKey;
const senderEmail = d.from?.emailAddress?.address || d.sender?.emailAddress?.address || String(d.from || 'unknown');
return [{ json: {
  source_channel: 'outlook',
  sender_id: senderEmail,
  sender_email: senderEmail,
  has_document: hasDoc,
  text: d.bodyPreview || '',
  subject: d.subject || '',
  filename: (attachKey && b[attachKey]) ? b[attachKey].fileName : null,
  attachment_key: attachKey,
  raw: d
}, binary: b }];

const resp = $input.first().json.response || 'No response from finance assistant.';
const orig = $('Has Document?').item.json;
return [{ json: { ...orig, ai_response: resp } }];

const d = $json;
const filename = (d.filename || '').toLowerCase();
const subject = (d.subject || d.text || '').toLowerCase();
let doc_type = 'invoice';
if (subject.includes('tax') || subject.includes('hmrc') || subject.includes('irs') || subject.includes('self assessment') || subject.includes('paye') || subject.includes('p60') || subject.includes('p45') || subject.includes('corporation tax') || filename.includes('tax') || filename.includes('hmrc')) {
  doc_type = 'tax_letter';
} else if (filename.endsWith('.csv') || filename.endsWith('.xlsx') || filename.endsWith('.xls') || filename.endsWith('.ods') || subject.includes('bank statement') || subject.includes('reconciliation') || subject.includes('statement of account')) {
  doc_type = 'table';
} else if (subject.includes('invoice') || subject.includes('receipt') || subject.includes('remittance') || filename.includes('invoice') || filename.includes('receipt')) {
  doc_type = 'invoice';
}
const useOcr = !filename || filename.endsWith('.pdf') || filename.endsWith('.jpg') || filename.endsWith('.jpeg') || filename.endsWith('.png') || filename.endsWith('.tiff') || filename.endsWith('.tif') || doc_type !== 'table';
return [{ json: { ...d, doc_type, use_ocr: useOcr } }];

const resp = $input.first().json.response || '{}';
let orig = {};
try { orig = $('Detect Document Type').item.json; } catch(e) {}
let parsed;
try {
  const match = resp.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : resp);
} catch(e) {
  parsed = { vendor: 'Unknown', document_type: orig.doc_type || 'unknown', amount: 0, description: resp.substring(0,300) };
}
return [{ json: {
  vendor: parsed.vendor || 'Unknown',
  document_type: parsed.document_type || orig.doc_type || 'invoice',
  reference_number: parsed.reference_number || 'N/A',
  date: parsed.date || new Date().toISOString().split('T')[0],
  due_date: parsed.due_date || null,
  amount: parseFloat(parsed.amount || 0),
  tax_amount: parseFloat(parsed.tax_amount || 0),
  currency: parsed.currency || 'GBP',
  description: parsed.description || '',
  key_details: parsed.key_details || JSON.stringify(parsed),
  line_items: parsed.line_items || [],
  source_channel: orig.source_channel || parsed.source_channel || 'unknown',
  sender_id: orig.sender_id || parsed.sender_id || 'unknown',
  sender_email: orig.sender_email || parsed.sender_email || null,
  doc_type: orig.doc_type || parsed.doc_type || 'invoice',
  subject: orig.subject || ''
} }];

const resp = $input.first().json.response || '{}';
let origData = {};
try { origData = $('Normalize Mindee Output').item.json; } catch(e) {}
if (!origData.source_channel) { try { origData = $('Parse AI Extract').item.json; } catch(e) {} }
if (!origData.source_channel) { try { origData = $('Parse Table / CSV').item.json; } catch(e) {} }
let parsed;
try {
  const match = resp.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : resp);
} catch(e) { parsed = {}; }
return [{ json: {
  ...origData,
  ...parsed,
  source_channel: origData.source_channel || 'unknown',
  sender_id: origData.sender_id || 'unknown',
  sender_email: origData.sender_email || null,
  doc_type: origData.doc_type || parsed.document_type || 'invoice',
  amount: parseFloat(parsed.amount || origData.amount || 0),
  tax_amount: parseFloat(parsed.tax_amount || origData.tax_amount || 0),
  currency: parsed.currency || origData.currency || 'GBP',
  date: parsed.date || origData.date || new Date().toISOString().split('T')[0]
} }];

const resp = $input.first().json.response || '{}';
let origData = {};
try { origData = $('Parse Enhanced Extraction').item.json; } catch(e) {}
let parsed;
try {
  const match = resp.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : resp);
} catch(e) {
  parsed = { category: 'Uncategorized', anomaly_flag: true, anomaly_severity: 'high', anomaly_reason: 'Parse failure — manual review needed', anomaly_recommendations: ['Manual review required'], confidence_score: 0, priority: 'high', action_required: 'Manual review' };
}
return [{ json: {
  ...origData,
  ...parsed,
  anomaly_recommendations: Array.isArray(parsed.anomaly_recommendations) ? parsed.anomaly_recommendations.join('; ') : (parsed.anomaly_recommendations || ''),
  processed_date: new Date().toISOString()
} }];

