const d = $input.first().json;
const icon = d.anomaly_flag ? '⚠️' : '✅';
const status = d.anomaly_flag ? 'Flagged for review: ' + d.anomaly_reason : 'No anomalies — processed successfully';
const text = icon + ' *Document Processed*

*Vendor:* ' + (d.vendor||'Unknown') + '
*Amount:* ' + (d.currency||'GBP') + ' ' + (d.amount||0) + '
*Type:* ' + (d.doc_type||'document') + '
*Category:* ' + (d.category||'Uncategorized') + '
*Date:* ' + (d.date||'N/A') + '

' + status;
return [{ json: { ...d, confirmation_text: text } }];

const resp = $input.first().json.response || '';
const emailMatch = resp.match(/\[EMAIL_FORMAT\]([\s\S]*?)\[\/EMAIL_FORMAT\]/);
const msgMatch = resp.match(/\[MSG_FORMAT\]([\s\S]*?)\[\/MSG_FORMAT\]/);
const emailContent = emailMatch ? emailMatch[1].trim() : resp;
const msgContent = msgMatch ? msgMatch[1].trim() : resp.substring(0, 800);
return [{ json: { email_content: emailContent, msg_content: msgContent } }];

